INSERT INTO public.passages VALUES ('48f287f8-b916-47dc-87b1-cc4beee3f084', '456216d0-cf0d-44b5-a570-410b7a0fb079', 'PASSAGE 3', '<p class="MsoNormal"><span style="font-size: 14pt;"><strong>On art and artists</strong></span></p>
